import{_ as e,c as l,o as i,ah as r}from"./chunks/framework.Cnj7lwEt.js";const x=JSON.parse('{"title":"Nginx Proxy Manager","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/运维工具/Nginx-Proxy-Manager-运维工具.md","filePath":"github汇总/运维工具/Nginx-Proxy-Manager-运维工具.md"}'),o={name:"github汇总/运维工具/Nginx-Proxy-Manager-运维工具.md"};function n(h,a,c,t,d,s){return i(),l("div",null,a[0]||(a[0]=[r('<h1 id="nginx-proxy-manager" tabindex="-1">Nginx Proxy Manager <a class="header-anchor" href="#nginx-proxy-manager" aria-label="Permalink to “Nginx Proxy Manager”">​</a></h1><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>Nginx Proxy Manager</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>运维工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>配置Nginx反向代理需要自己写配置文件，处理SSL证书申请和续期特别麻烦</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><ul><li>基于Docker的Nginx反向代理管理工具</li><li>友好的Web界面</li><li>支持HTTP和TCP转发</li><li>支持自定义Nginx配置</li><li>自动申请和续期Let&#39;s Encrypt SSL证书</li><li>支持多个用户和访问控制</li><li>安全日志</li><li>Docker Compose一键部署</li><li>Docker镜像可用</li></ul><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>友好的Web界面，可视化操作，不用记命令</li><li>支持HTTP和TCP转发</li><li>支持自定义Nginx配置</li><li>自动申请和续期Let&#39;s Encrypt SSL证书，无需手动操作</li><li>支持多个用户和访问控制</li><li>安全日志功能</li><li>部署超简单，Docker Compose一条命令就能搞定</li><li>Docker镜像直接可用</li><li>最受欢迎的Nginx反向代理管理工具之一</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/NginxProxyManager/nginx-proxy-manager" target="_blank" rel="noreferrer">https://github.com/NginxProxyManager/nginx-proxy-manager</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>适用于运维人员、自托管爱好者和家庭服务器用户，支持Docker环境</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li>系统要求：支持Windows、macOS、Linux</li><li>Docker环境：已安装Docker和Docker Compose <ul><li>检查命令：<code>docker --version</code> 和 <code>docker-compose --version</code></li><li>通过标准：Docker正常可用</li></ul></li><li>网络连接：可访问互联网</li><li>域名：需要有域名指向服务器（用于SSL证书）</li></ol><h3 id="主路径-docker-compose部署" tabindex="-1">主路径：Docker Compose部署 <a class="header-anchor" href="#主路径-docker-compose部署" aria-label="Permalink to “主路径：Docker Compose部署”">​</a></h3><h4 id="步骤1-创建docker-compose-yml" tabindex="-1">步骤1：创建docker-compose.yml <a class="header-anchor" href="#步骤1-创建docker-compose-yml" aria-label="Permalink to “步骤1：创建docker-compose.yml”">​</a></h4><ul><li>步骤目标：创建Docker Compose配置文件</li><li>执行位置：项目目录</li><li>完整内容：创建docker-compose.yml文件，包含Nginx Proxy Manager服务配置</li><li>成功标志：配置文件创建完成</li><li>失败处理：检查Docker Compose配置语法</li></ul><h4 id="步骤2-启动服务" tabindex="-1">步骤2：启动服务 <a class="header-anchor" href="#步骤2-启动服务" aria-label="Permalink to “步骤2：启动服务”">​</a></h4><ul><li>步骤目标：启动Nginx Proxy Manager</li><li>执行位置：项目目录</li><li>完整命令：<code>docker-compose up -d</code></li><li>成功标志：容器启动成功</li><li>失败处理：检查Docker环境，查看容器日志</li></ul><h4 id="步骤3-访问管理界面" tabindex="-1">步骤3：访问管理界面 <a class="header-anchor" href="#步骤3-访问管理界面" aria-label="Permalink to “步骤3：访问管理界面”">​</a></h4><ul><li>步骤目标：访问Web管理界面</li><li>执行位置：浏览器</li><li>访问地址：http://[服务器IP]:81</li><li>默认邮箱：admin@example.com</li><li>默认密码：changeme</li><li>成功标志：能看到登录界面</li><li>失败处理：检查端口81是否被占用，检查容器是否正常运行</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ol><li>访问地址：http://[服务器IP]:81</li><li>官方文档：<a href="https://nginxproxymanager.com" target="_blank" rel="noreferrer">https://nginxproxymanager.com</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ol><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li>现象：容器启动失败 <ul><li>可能原因：端口占用或配置错误</li><li>解决步骤：检查端口80、443、81是否被占用，检查docker-compose.yml配置</li></ul></li><li>现象：SSL证书申请失败 <ul><li>可能原因：域名解析问题或网络问题</li><li>解决步骤：确认域名正确解析到服务器，检查网络连接</li></ul></li><li>现象：无法访问管理界面 <ul><li>可能原因：防火墙或端口问题</li><li>解决步骤：检查防火墙设置，确认端口81未被占用</li></ul></li></ol><h3 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h3><p>如需深入了解详细配置和使用方法，可访问官方网站：<a href="https://nginxproxymanager.com" target="_blank" rel="noreferrer">https://nginxproxymanager.com</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',33)]))}const p=e(o,[["render",n]]);export{x as __pageData,p as default};
